#include<bits/stdc++.h>
using namespace std;

int n,m,k;
int a[111][111],b[111][111],c[111][111];
int main(){
    cin>>n>>m>>k;
    for(int i=1;i<=n;i++) for(int j=1;j<=m;j++) cin>>a[i][j];
    for(int i=1;i<=m;i++) for(int j=1;j<=k;j++) cin>>b[i][j];
    for(int i=1;i<=n;i++){ 
        for(int j=1;j<=k;j++){ 
            int ans=0;
            for(int l=1;l<=m;l++){
                ans+=(a[i][l]*b[l][j]);
            }
            cout<<ans<<' ';
        }
        cout<<'\n';
    }
    return 0;
}
